const body = $input.first().json.body;
const states = Array.isArray(body) ? body : JSON.parse(body);

// Slim list for Gemini — no screenshots
const stateList = states.map((s, i) => ({
  index: i,
  title: s.title,
  fullPath: s.fullPath,
  module: s.module,
  url: s.url,
  bbox: s.bbox
}));

// Full data stored separately — screenshots included
// Store as separate key so Gemini never sees screenshots
return [{ json: { 
  states: stateList,
  // Store screenshots in a lookup by index
  screenshots: states.reduce((acc, s, i) => {
    acc[i] = s.screenshot;
    return acc;
  }, {}),
  bboxes: states.reduce((acc, s, i) => {
    acc[i] = s.bbox;
    return acc;
  }, {})
}}];

