const geminiResponse = $input.item.json;
const sourceData = $node["Code in JavaScript"].json;

let flowsJson = '';
try {
  flowsJson = geminiResponse.candidates[0].content.parts[0].text.trim();
  flowsJson = flowsJson.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
} catch(e) {
  throw new Error('Failed to parse Gemini response: ' + JSON.stringify(geminiResponse));
}

let flows;
try {
  flows = JSON.parse(flowsJson);
} catch(e) {
  throw new Error('Invalid JSON from Gemini: ' + flowsJson.substring(0, 500));
}

const states = sourceData.states;
const screenshots = sourceData.screenshots;
const bboxes = sourceData.bboxes;

const enrichedFlows = flows.map(flow => ({
  ...flow,
  steps: flow.steps.map(step => {
    // Handle both {index, tooltip} object or plain number
    const idx = typeof step === 'object' ? step.index : step;
    const tooltip = typeof step === 'object' ? (step.tooltip || '') : '';
    const state = states[idx];
    if (!state) return null;
    return {
      index: idx,
      title: state.title,
      fullPath: state.fullPath,
      url: state.url,
      bbox: bboxes[idx] || { x: 45, y: 45, w: 10, h: 10 },
      screenshot: screenshots[idx],
      tooltip: tooltip || state.title
    };
  }).filter(Boolean)
})).filter(f => f.steps.length > 0);

console.log('Total flows:', enrichedFlows.length);
return enrichedFlows.map(flow => ({ json: flow }));

const items = $input.all();
const results = [];

for (const item of items) {
  const flow = item.json;
  const steps = Array.isArray(flow.steps) ? flow.steps : [];
  const title = flow.name || 'Demo';
  const fileName = title.replace(/[^a-z0-9]/gi, '-').toLowerCase() + '.html';

  const stepsData = steps.map((step, i) => ({
    index: i,
    title: step.title || 'Step ' + (i+1),
    tooltip: step.tooltip || step.title || 'Click to continue.',
    bbox: step.bbox || { x: 45, y: 45, w: 10, h: 10 },
    screenshot: step.screenshot || ''
  }));

  const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<title>${title}</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, sans-serif; background: #0f0f0f; color: #fff; min-height: 100vh; display: flex; flex-direction: column; align-items: center; padding: 24px; }
h1 { font-size: 20px; font-weight: 600; margin-bottom: 8px; opacity: 0.9; }
.meta { font-size: 13px; opacity: 0.4; margin-bottom: 20px; }
.step-label { font-size: 14px; opacity: 0.7; margin-bottom: 10px; font-weight: 500; }
.demo-wrap { position: relative; display: inline-block; }
.demo-wrap img { display: block; width: 960px; max-width: 90vw; border-radius: 10px; box-shadow: 0 8px 40px rgba(0,0,0,0.6); }
.ring {
  position: absolute;
  border: 3px solid #ff3333;
  border-radius: 6px;
  box-shadow: 0 0 0 4px rgba(255,51,51,0.25), 0 0 20px rgba(255,51,51,0.5);
  pointer-events: none;
  animation: pulse 1.5s ease-in-out infinite;
}
@keyframes pulse {
  0%, 100% { box-shadow: 0 0 0 4px rgba(255,51,51,0.25), 0 0 20px rgba(255,51,51,0.5); }
  50% { box-shadow: 0 0 0 8px rgba(255,51,51,0.1), 0 0 36px rgba(255,51,51,0.7); }
}
.tooltip {
  position: absolute;
  background: rgba(15,15,15,0.95);
  color: #fff;
  font-size: 13px;
  padding: 12px 16px;
  border-radius: 8px;
  max-width: 240px;
  line-height: 1.6;
  pointer-events: none;
  border-left: 3px solid #ff3333;
  backdrop-filter: blur(8px);
  box-shadow: 0 4px 20px rgba(0,0,0,0.4);
}
.nav { display: flex; align-items: center; gap: 12px; margin-top: 20px; flex-wrap: wrap; justify-content: center; }
.nav button {
  background: rgba(255,255,255,0.1);
  color: #fff;
  border: 1px solid rgba(255,255,255,0.15);
  padding: 10px 24px;
  border-radius: 8px;
  font-size: 14px;
  cursor: pointer;
  transition: background 0.2s;
}
.nav button:hover { background: rgba(255,255,255,0.2); }
.nav button:disabled { opacity: 0.3; cursor: default; }
.nav .counter { font-size: 13px; opacity: 0.5; min-width: 60px; text-align: center; }
.speak-btn {
  background: rgba(255,51,51,0.15);
  border: 1px solid rgba(255,51,51,0.4);
  color: #ff6666;
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 13px;
  cursor: pointer;
  transition: background 0.2s;
}
.speak-btn:hover { background: rgba(255,51,51,0.3); }
.speak-btn.speaking { background: rgba(255,51,51,0.4); }
.dots { display: flex; gap: 6px; margin-top: 14px; }
.dot { width: 8px; height: 8px; border-radius: 50%; background: rgba(255,255,255,0.2); cursor: pointer; transition: background 0.2s; }
.dot.active { background: #ff3333; }
.progress { width: 960px; max-width: 90vw; height: 2px; background: rgba(255,255,255,0.1); border-radius: 2px; margin-bottom: 12px; }
.progress-bar { height: 100%; background: #ff3333; border-radius: 2px; transition: width 0.3s ease; }
</style>
</head>
<body>
<h1>${title}</h1>
<div class="meta">${flow.description || ''} &nbsp;·&nbsp; ${steps.length} step${steps.length !== 1 ? 's' : ''}</div>
<div class="progress"><div class="progress-bar" id="progressBar"></div></div>
<div class="step-label" id="stepLabel"></div>
<div class="demo-wrap" id="demoWrap">
  <img id="screenshot" src="" alt="Demo screenshot" />
  <div class="ring" id="ring"></div>
  <div class="tooltip" id="tooltip"></div>
</div>
<div class="nav">
  <button id="prevBtn" onclick="go(-1)" disabled>← Back</button>
  <span class="counter" id="counter"></span>
  <button id="nextBtn" onclick="go(1)">Next →</button>
  <button class="speak-btn" id="speakBtn" onclick="speak()">🔊 Listen</button>
</div>
<div class="dots" id="dots"></div>

<script>
const steps = ${JSON.stringify(stepsData)};
let current = 0;
let speaking = false;

function render() {
  const s = steps[current];
  const img = document.getElementById('screenshot');
  const ring = document.getElementById('ring');
  const tooltip = document.getElementById('tooltip');

  img.src = 'data:image/png;base64,' + s.screenshot;

  ring.style.left = s.bbox.x + '%';
  ring.style.top = s.bbox.y + '%';
  ring.style.width = s.bbox.w + '%';
  ring.style.height = s.bbox.h + '%';

  const tipLeft = Math.min(s.bbox.x + s.bbox.w + 1, 62);
  tooltip.style.left = tipLeft + '%';
  tooltip.style.top = Math.max(s.bbox.y, 2) + '%';
  tooltip.textContent = s.tooltip;

  document.getElementById('stepLabel').textContent = 'Step ' + (current+1) + ' of ' + steps.length + ': ' + s.title;
  document.getElementById('counter').textContent = (current+1) + ' / ' + steps.length;
  document.getElementById('prevBtn').disabled = current === 0;
  document.getElementById('nextBtn').disabled = current === steps.length - 1;
  document.getElementById('progressBar').style.width = ((current+1)/steps.length*100) + '%';

  document.querySelectorAll('.dot').forEach((d,i) => d.classList.toggle('active', i===current));
}

function go(dir) {
  window.speechSynthesis && window.speechSynthesis.cancel();
  current = Math.max(0, Math.min(steps.length-1, current + dir));
  render();
}

function speak() {
  if (!window.speechSynthesis) return;
  const s = steps[current];
  const text = 'Step ' + (current+1) + ' of ' + steps.length + '. ' + s.title + '. ' + s.tooltip;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  utterance.rate = 0.85;
  utterance.pitch = 1;
  const btn = document.getElementById('speakBtn');
  utterance.onstart = () => btn.classList.add('speaking');
  utterance.onend = () => btn.classList.remove('speaking');
  window.speechSynthesis.speak(utterance);
}

// Build dots
const dotsEl = document.getElementById('dots');
steps.forEach((_, i) => {
  const d = document.createElement('div');
  d.className = 'dot' + (i===0?' active':'');
  d.onclick = () => { window.speechSynthesis && window.speechSynthesis.cancel(); current = i; render(); };
  dotsEl.appendChild(d);
});

window.onload = render;
</script>
</body>
</html>`;

  const buf = Buffer.from(html, 'utf8');
  const binaryData = await this.helpers.prepareBinaryData(buf, fileName, 'text/html');

  results.push({
    json: {
      title: title,
      module: String(flow.module || ''),
      fileName: fileName
    },
    binary: {
      data: binaryData
    }
  });
}

return results;
